import { useState } from 'react';
import './App.css';
import Api from './axios/api';
import { json } from 'stream/consumers';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 const dados = await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>response.data )  
  .catch((e)=> console.log(e));

  console.log(dados);
}



  return (
    <div style={container}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
    <div style={{display:"flex",backgroundColor:"blue", color:"white", padding:"20px"}}>
      {usuarios[0].nome}
       {usuarios.map((usuario)=>
        <div>
          <h2>{usuario.id}</h2>
           <h2>{usuario.nome}</h2>
          </div>
       )}  
    </div>
    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>
    </div> 
  );
}

export default App;

